import{_ as a,o as s,c as i,ag as t}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Configuration","description":"Environment variables, excluded-folder rules, path behavior, and scan controls in Foldergram.","frontmatter":{"title":"Configuration","description":"Environment variables, excluded-folder rules, path behavior, and scan controls in Foldergram."},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":1775244546000}'),d={name:"configuration.md"};function o(n,e,r,l,c,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>For source installs, Foldergram reads <code>.env</code> from the repository root and validates it in <code>server/src/config/env.ts</code>.</p><p>In the default Docker Compose setup, the container uses the image&#39;s built-in production defaults plus the mounted <code>./data/...</code> volumes. The source-install <code>.env</code> file is not read directly inside the container unless you wire that in yourself.</p><h2 id="environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>NODE_ENV</code></td><td><code>development</code></td><td>Must be <code>development</code>, <code>test</code>, or <code>production</code>.</td></tr><tr><td><code>SERVER_PORT</code></td><td><code>4141</code></td><td>Production Express port. Used by Docker and <code>pnpm start</code>.</td></tr><tr><td><code>DEV_SERVER_PORT</code></td><td><code>4140</code></td><td>Express server port during <code>pnpm dev</code>.</td></tr><tr><td><code>DEV_CLIENT_PORT</code></td><td><code>4141</code></td><td>Base Vite dev server port during <code>pnpm dev</code>. The client may fall forward through <code>4144</code>. The same range is allowed for non-production local-origin mutation checks.</td></tr><tr><td><code>DATA_ROOT</code></td><td><code>./data</code></td><td>Base directory for app-managed storage. Other storage paths default under it unless overridden.</td></tr><tr><td><code>DATA_DIR</code></td><td>unset</td><td>Optional alias that falls back into <code>DATA_ROOT</code> resolution when <code>DATA_ROOT</code> is absent.</td></tr><tr><td><code>GALLERY_ROOT</code></td><td><code>./data/gallery</code></td><td>Source media root. Foldergram scans below this path.</td></tr><tr><td><code>GALLERY_EXCLUDED_FOLDERS</code></td><td>unset</td><td>Comma-separated folder exclusion rules. Names match anywhere in the gallery tree; values with a slash match one exact relative path below <code>GALLERY_ROOT</code>.</td></tr><tr><td><code>DB_DIR</code></td><td><code>./data/db</code></td><td>SQLite directory. Database file is <code>gallery.sqlite</code>.</td></tr><tr><td><code>THUMBNAILS_DIR</code></td><td><code>./data/thumbnails</code></td><td>Generated thumbnail output root.</td></tr><tr><td><code>PREVIEWS_DIR</code></td><td><code>./data/previews</code></td><td>Generated preview output root.</td></tr><tr><td><code>IMAGE_DETAIL_SOURCE</code></td><td><code>preview</code></td><td>For image detail pages, use generated previews or stream originals. Videos ignore this flag.</td></tr><tr><td><code>DERIVATIVE_MODE</code></td><td><code>eager</code></td><td>Generate derivatives during scans or lazily on the first protected derivative request.</td></tr><tr><td><code>LOG_VERBOSE</code></td><td><code>0</code></td><td>Truthy values are <code>1</code>, <code>true</code>, <code>yes</code>, and <code>on</code>.</td></tr><tr><td><code>SCAN_DISCOVERY_CONCURRENCY</code></td><td><code>4</code></td><td>Discovery concurrency, validated from <code>1</code> to <code>32</code>.</td></tr><tr><td><code>SCAN_DERIVATIVE_CONCURRENCY</code></td><td><code>4</code></td><td>Derivative concurrency, validated from <code>1</code> to <code>32</code>.</td></tr><tr><td><code>PUBLIC_DEMO_MODE</code></td><td><code>0</code></td><td>When enabled, mutating API routes return <code>403</code> for read-only demo deployments.</td></tr><tr><td><code>CSRF_TRUSTED_ORIGINS</code></td><td>unset</td><td>Comma-separated extra browser origins allowed for mutating API requests. Useful behind reverse proxies or HTTPS terminators.</td></tr></tbody></table><h2 id="access-protection-configuration" tabindex="-1">Access protection configuration <a class="header-anchor" href="#access-protection-configuration" aria-label="Permalink to &quot;Access protection configuration&quot;">​</a></h2><p>Shared-password protection is <strong>not</strong> configured in <code>.env</code>.</p><p>Instead:</p><ul><li>enable it from the Settings page</li><li>Foldergram stores the password hash and session metadata in SQLite <code>app_settings</code></li><li>deleting or replacing the SQLite database resets the configured password protection state</li></ul><p>The built-in auth model is a small role-based password gate for one app instance, not a multi-user account system.</p><h2 id="stories-folders-mode" tabindex="-1">Stories folders mode <a class="header-anchor" href="#stories-folders-mode" aria-label="Permalink to &quot;Stories folders mode&quot;">​</a></h2><p>Reserved stories behavior is <strong>not</strong> configured in <code>.env</code>.</p><p>Instead:</p><ul><li>Foldergram stores the current stories-folders mode in SQLite <code>app_settings</code></li><li>the Settings page exposes the toggle <code>Treat stories folders as normal app folders</code></li><li>the default mode is reserved stories, where <code>AppFolder/stories</code> powers avatar stories and highlight capsules</li><li>turning the toggle on enables legacy behavior, where folders literally named <code>stories</code> remain ordinary app folders</li><li>changing this setting requires a rescan because the indexed folder structure changes</li><li>if the existing library already contains candidate <code>stories/</code> folders, Settings can show a migration decision card until you choose a mode</li></ul><h2 id="excluded-folders" tabindex="-1">Excluded folders <a class="header-anchor" href="#excluded-folders" aria-label="Permalink to &quot;Excluded folders&quot;">​</a></h2><p>Folder exclusions can come from two places:</p><ul><li><code>GALLERY_EXCLUDED_FOLDERS</code> in <code>.env</code> or Docker Compose</li><li>custom rules saved from <code>Settings -&gt; General Settings</code></li></ul><p>Behavior:</p><ul><li>rules without a slash match folder names anywhere in the gallery tree, such as <code>@eaDir</code> or <code>thumbnails</code></li><li>rules with a slash match one exact relative folder path under <code>GALLERY_ROOT</code>, such as <code>Archive/cache</code></li><li>env-backed rules appear read-only in <code>General Settings</code></li><li>custom rules are stored in SQLite <code>app_settings</code> and can be changed at runtime</li><li>after changing custom rules, run a full scan from <code>Settings -&gt; Scan &amp; Library</code> so already-indexed matches are soft-removed from the library</li></ul><h2 id="settings-sections" tabindex="-1">Settings sections <a class="header-anchor" href="#settings-sections" aria-label="Permalink to &quot;Settings sections&quot;">​</a></h2><p>The Settings sidebar is split into:</p><ul><li><code>Scan &amp; Library</code> for manual scans, thumbnail rebuilds, and library-index rebuilds</li><li><code>General Settings</code> for Home/Reels defaults, stories-folders mode, excluded folders, and any save-and-rescan notices tied to those app-wide rules</li><li><code>Security &amp; Access</code> for admin, viewer, and public-mode controls</li><li><code>System Status</code> for storage, index, and last-scan details</li></ul><h2 id="path-resolution-rules" tabindex="-1">Path resolution rules <a class="header-anchor" href="#path-resolution-rules" aria-label="Permalink to &quot;Path resolution rules&quot;">​</a></h2><ul><li><code>DATA_ROOT</code> is the common fallback parent for the app&#39;s storage directories.</li><li>If you set only <code>DATA_ROOT=/mnt/foldergram</code>, the default paths become <code>/mnt/foldergram/gallery</code>, <code>/mnt/foldergram/db</code>, <code>/mnt/foldergram/thumbnails</code>, and <code>/mnt/foldergram/previews</code>.</li><li>Setting <code>GALLERY_ROOT</code>, <code>DB_DIR</code>, <code>THUMBNAILS_DIR</code>, or <code>PREVIEWS_DIR</code> overrides only that specific path.</li><li><code>DATA_DIR</code> is a legacy alias. It is used only when <code>DATA_ROOT</code> is unset.</li><li>Relative paths are resolved from the repository root.</li><li>Absolute paths are used as-is.</li><li><code>THUMBNAILS_DIR</code> and <code>PREVIEWS_DIR</code> must be separate, non-overlapping directories.</li><li><code>THUMBNAILS_DIR</code> cannot contain <code>GALLERY_ROOT</code>.</li><li><code>PREVIEWS_DIR</code> cannot contain <code>GALLERY_ROOT</code>.</li><li><code>GALLERY_ROOT</code> only needs read access for scans and originals.</li><li><code>DB_DIR</code>, <code>THUMBNAILS_DIR</code>, and <code>PREVIEWS_DIR</code> must be writable.</li></ul><p>Foldergram normalizes path separators so the same rules work with POSIX-style and Windows-style paths.</p><h2 id="detail-source-and-derivative-timing" tabindex="-1">Detail source and derivative timing <a class="header-anchor" href="#detail-source-and-derivative-timing" aria-label="Permalink to &quot;Detail source and derivative timing&quot;">​</a></h2><h3 id="image-detail-source" tabindex="-1"><code>IMAGE_DETAIL_SOURCE</code> <a class="header-anchor" href="#image-detail-source" aria-label="Permalink to &quot;\`IMAGE_DETAIL_SOURCE\`&quot;">​</a></h3><p>Accepted values:</p><ul><li><code>preview</code></li><li><code>original</code></li></ul><p>Behavior:</p><ul><li>applies to image detail pages only</li><li><code>preview</code> keeps <code>/image/:id</code> on generated preview assets</li><li><code>original</code> makes image detail pages use <code>/api/originals/:id</code></li><li>does not change feed cards, folder grids, avatars, or other list surfaces</li><li>does not change video default playback behavior</li></ul><h3 id="derivative-mode" tabindex="-1"><code>DERIVATIVE_MODE</code> <a class="header-anchor" href="#derivative-mode" aria-label="Permalink to &quot;\`DERIVATIVE_MODE\`&quot;">​</a></h3><p>Accepted values:</p><ul><li><code>eager</code></li><li><code>lazy</code></li></ul><p>Behavior:</p><ul><li><code>eager</code> generates thumbnails and previews during scans</li><li><code>lazy</code> still indexes metadata during scans, but missing files are generated on the first request to <code>/thumbnails/...</code> or <code>/previews/...</code> and then cached on disk</li><li>lazy mode applies to thumbnails and previews</li><li>lazy mode keeps derivative URLs deterministic because the stored asset-key derivative paths are still persisted in SQLite</li></ul><h3 id="recommended-combinations" tabindex="-1">Recommended combinations <a class="header-anchor" href="#recommended-combinations" aria-label="Permalink to &quot;Recommended combinations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Goal</th><th>Suggested config</th></tr></thead><tbody><tr><td>Current behavior</td><td><code>IMAGE_DETAIL_SOURCE=preview</code>, <code>DERIVATIVE_MODE=eager</code></td></tr><tr><td>Lowest upfront processing for large libraries</td><td><code>IMAGE_DETAIL_SOURCE=original</code>, <code>DERIVATIVE_MODE=lazy</code></td></tr></tbody></table><h3 id="settings-actions-and-lazy-mode" tabindex="-1">Settings actions and lazy mode <a class="header-anchor" href="#settings-actions-and-lazy-mode" aria-label="Permalink to &quot;Settings actions and lazy mode&quot;">​</a></h3><ul><li><code>Scan Library</code> always refreshes index metadata.</li><li><code>Rebuild Library Index</code> resets and rebuilds the SQLite-backed index. Existing sharded derivatives remain reusable when the same indexed rows survive the upgrade path.</li><li>In <code>DERIVATIVE_MODE=lazy</code>, neither a normal scan nor <code>Rebuild Library Index</code> pre-generates missing thumbnails or previews.</li><li><code>Regenerate Thumbnails</code> remains a manual thumbnail and video-poster rebuild only. It does not rebuild previews.</li><li>Runtime-only app-wide controls such as stories mode and excluded folders live under <code>Settings -&gt; General Settings</code>, while the scan and rebuild actions live under <code>Settings -&gt; Scan &amp; Library</code>.</li></ul><h2 id="derivative-layout-upgrade" tabindex="-1">Derivative layout upgrade <a class="header-anchor" href="#derivative-layout-upgrade" aria-label="Permalink to &quot;Derivative layout upgrade&quot;">​</a></h2><p>Recent versions store derivatives under sharded asset-key paths instead of mirroring the gallery tree. Existing libraries migrate on the next full scan:</p><ul><li>current derivative paths use a single shard segment based on the first two hex characters of <code>asset_key</code>, such as <code>thumbnails/ab/&lt;asset_key&gt;.webp</code> and <code>previews/ab/&lt;asset_key&gt;.webp</code></li><li>old mirrored rows keep working until the migration runs</li><li>the migration backfills <code>asset_key</code> and moves derivative files in place</li><li>stored derivative paths are updated only when the destination file already exists</li><li>if a legacy derivative still exists but the stored path is broken, the next full scan repairs it before falling back to regeneration</li><li>after migration, full rescans can preserve the same indexed media identity across safe folder moves</li><li>stale derivatives from soft-deleted files are cleaned up after the retention window on later successful full scans</li></ul><h2 id="live-scan-progress" tabindex="-1">Live scan progress <a class="header-anchor" href="#live-scan-progress" aria-label="Permalink to &quot;Live scan progress&quot;">​</a></h2><p>Foldergram exposes live scan state in three places:</p><ul><li><code>GET /api/status</code> includes the current viewer-safe <code>scan</code> snapshot alongside broader shell status</li><li><code>GET /api/scan-progress</code> returns the same viewer-safe scan payload on its own for lighter polling</li><li><code>GET /api/admin/scan-progress</code> returns the admin-detailed scan payload, including current file and folder detail when available</li></ul><p>Scan phases behave as follows:</p><ul><li><code>migration</code> is determinate and reports checked rows, moved files, repaired files, missing files, and asset-key backfills</li><li><code>discovery</code> reports discovered and processed folders and posts, but remains open-ended while the scanner is still finding additional folders</li><li><code>derivatives</code> is determinate and reports queued-versus-completed jobs plus generated thumbnails and previews</li></ul><h2 id="managed-path-ignores" tabindex="-1">Managed path ignores <a class="header-anchor" href="#managed-path-ignores" aria-label="Permalink to &quot;Managed path ignores&quot;">​</a></h2><p>If your configured database, thumbnails, or previews directories live inside the gallery tree, Foldergram computes their relative paths and excludes them from discovery. That prevents generated files from being re-indexed as source media.</p><h2 id="recommended-local-env" tabindex="-1">Recommended local <code>.env</code> <a class="header-anchor" href="#recommended-local-env" aria-label="Permalink to &quot;Recommended local \`.env\`&quot;">​</a></h2><p><code>.env.example</code> groups the main runtime settings in the same order shown above. Production runtimes still use <code>SERVER_PORT</code>, which defaults to <code>4141</code> unless you override it in Docker Compose or at process start.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">NODE_ENV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">development</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SERVER_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4141</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEV_SERVER_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4140</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEV_CLIENT_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4141</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DATA_ROOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./data</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GALLERY_ROOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./data/gallery</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GALLERY_EXCLUDED_FOLDERS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DB_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./data/db</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">THUMBNAILS_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./data/thumbnails</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PREVIEWS_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./data/previews</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">IMAGE_DETAIL_SOURCE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">preview</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DERIVATIVE_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">eager</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LOG_VERBOSE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SCAN_DISCOVERY_CONCURRENCY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SCAN_DERIVATIVE_CONCURRENCY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PUBLIC_DEMO_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CSRF_TRUSTED_ORIGINS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span></span></code></pre></div><h2 id="concurrency-tuning" tabindex="-1">Concurrency tuning <a class="header-anchor" href="#concurrency-tuning" aria-label="Permalink to &quot;Concurrency tuning&quot;">​</a></h2><p><code>SCAN_DISCOVERY_CONCURRENCY</code> affects filesystem stat and metadata discovery work. <code>SCAN_DERIVATIVE_CONCURRENCY</code> affects Sharp and FFmpeg jobs.</p><p>Practical guidance:</p><ul><li>Keep the defaults on smaller machines.</li><li>Increase discovery concurrency only when storage is fast enough to benefit.</li><li>Increase derivative concurrency only when CPU, RAM, and disk bandwidth can handle it.</li></ul><h2 id="gallery-structure-expectations" tabindex="-1">Gallery structure expectations <a class="header-anchor" href="#gallery-structure-expectations" aria-label="Permalink to &quot;Gallery structure expectations&quot;">​</a></h2><p>Foldergram ignores files placed directly in <code>GALLERY_ROOT</code>.</p><p>It indexes only folders that directly contain supported media:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gallery/</span></span>
<span class="line"><span>  loose-file.jpg         # ignored</span></span>
<span class="line"><span>  trips/</span></span>
<span class="line"><span>    oslo/</span></span>
<span class="line"><span>      IMG_0001.jpg       # indexed folder</span></span>
<span class="line"><span>    berlin/</span></span>
<span class="line"><span>      notes.txt          # not indexed</span></span></code></pre></div><p>In the default reserved-stories mode, Foldergram also treats <code>AppFolder/stories</code> specially:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gallery/</span></span>
<span class="line"><span>  AnimalPlanet/</span></span>
<span class="line"><span>    post-1.jpg          # indexed owner folder media</span></span>
<span class="line"><span>    stories/</span></span>
<span class="line"><span>      story-1.mp4       # avatar story set</span></span>
<span class="line"><span>      Lions/</span></span>
<span class="line"><span>        clip-1.mp4      # highlight capsule</span></span>
<span class="line"><span>        nested-1/</span></span>
<span class="line"><span>          clip-2.jpg    # still part of Lions</span></span></code></pre></div><p>If you want folders literally named <code>stories</code> to remain ordinary app folders, enable <code>Treat stories folders as normal app folders</code> in Settings and rescan the library.</p><h2 id="gallery-root-changes" tabindex="-1">Gallery root changes <a class="header-anchor" href="#gallery-root-changes" aria-label="Permalink to &quot;Gallery root changes&quot;">​</a></h2><p>Foldergram stores the last successful gallery root in <code>app_settings</code>.</p><p>When the configured gallery root changes and there is already indexed content, Foldergram marks the library as requiring a rebuild. Until that rebuild happens:</p><ul><li>startup scanning is deferred</li><li>manual rescans return <code>409</code></li><li>thumbnail rebuilds return <code>409</code></li></ul><p>Viewer-safe shell status comes from <code>GET /api/status</code>, with dedicated live scan polling available from <code>GET /api/scan-progress</code>.</p><p>The current and previous gallery roots remain exposed only in <code>GET /api/admin/stats</code>. Admin-only live scan file and folder detail is available from <code>GET /api/admin/scan-progress</code> and from the <code>scan</code> field in <code>GET /api/admin/stats</code>.</p>`,70)])])}const g=a(d,[["render",o]]);export{u as __pageData,g as default};
